import{_ as t,o,c as a,a8 as n}from"./chunks/framework.DvHWw5tv.js";const u=JSON.parse('{"title":"useClassComputed","description":"","frontmatter":{},"headers":[],"relativePath":"en/design/hooks/useClass.md","filePath":"en/design/hooks/useClass.md"}'),s={name:"en/design/hooks/useClass.md"};function i(r,e,l,d,c,m){return o(),a("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776410922000"},[...e[0]||(e[0]=[n('<h1 id="useclasscomputed" tabindex="-1">useClassComputed <a class="header-anchor" href="#useclasscomputed" aria-label="Permalink to “useClassComputed”">​</a></h1><p>In the architecture of this component library, Hooks are the core bearers of the <strong>logic layer</strong>. They are not auxiliary logic attached to components, but independent, reusable abstraction units responsible for completely stripping recurring interaction and computation patterns away from components.</p><p>This directly reflects the &quot;layer separation&quot; philosophy:</p><ul><li><strong>Structure Layer</strong>: Only responsible for DOM layout</li><li><strong>Presentation Layer</strong>: Only responsible for style injection</li><li><strong>Logic Layer</strong>: Managed uniformly by Hooks</li></ul><p>The existence of Hooks makes component implementations extremely minimal—components only need to <strong>declare</strong> the required logic; all reactive computation and driving are handled by Hooks.</p><h2 id="dynamic-class-name-computation-hook" tabindex="-1">Dynamic Class Name Computation Hook <a class="header-anchor" href="#dynamic-class-name-computation-hook" aria-label="Permalink to “Dynamic Class Name Computation Hook”">​</a></h2><h3 id="pain-points" tabindex="-1">Pain Points <a class="header-anchor" href="#pain-points" aria-label="Permalink to “Pain Points”">​</a></h3><p>When developing UI components, one of the most common repetitive tasks is dynamically generating class names based on props. For example:</p><ul><li><code>size=&quot;large&quot;</code> → need to add <code>xxx--large</code></li><li><code>disabled={true}</code> → need to add <code>xxx--disabled</code></li><li><code>round={true}</code> → need to add <code>xxx--round</code></li></ul><p>Implementing such logic independently in each component leads to:</p><ul><li>Highly redundant code</li><li>Inconsistent naming conventions</li><li>Potential oversight of reactive updates</li><li>High maintenance costs when theme or naming conventions change (requires modifying each component individually)</li></ul><h2 id="design-goals" tabindex="-1">Design Goals <a class="header-anchor" href="#design-goals" aria-label="Permalink to “Design Goals”">​</a></h2><p>The goal of <code>useClassComputed</code> is to <strong>provide a unified, type-safe, and configurable mechanism</strong> that completely solves the dynamic class name generation needs for all components and strips this logic entirely from the component internals.</p><h2 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to “Core Features”">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>Reactive Output</strong></td><td>Returns a <code>ComputedRef&lt;string[]&gt;</code> that updates automatically with prop changes, perfectly aligning with Vue&#39;s reactivity system</td></tr><tr><td><strong>BEM-like Convention</strong></td><td>Default format <code>${baseClass}--${modifier}</code> ensures semantically clear and predictable class names</td></tr><tr><td><strong>Dual Generation Mechanism</strong></td><td><code>propClasses</code>: for valued properties (e.g., <code>size</code>, <code>type</code>) <br><code>flagClasses</code>: for boolean flags (e.g., <code>disabled</code>, <code>round</code>)</td></tr><tr><td><strong>Highly Customizable</strong></td><td>Supports custom formatter functions via <code>classNameFormatter</code> for scenarios like multi-level BEM or theme prefixes</td></tr><tr><td><strong>Type Safe</strong></td><td>Generic <code>&lt;T&gt;</code> strongly binds to component props, providing complete TypeScript type inference and IntelliSense</td></tr><tr><td><strong>Clear Boundaries</strong></td><td>Does not bind to DOM, handle style conflicts, or involve side effects (e.g., event listeners or DOM queries)</td></tr></tbody></table><h2 id="design-value" tabindex="-1">Design Value <a class="header-anchor" href="#design-value" aria-label="Permalink to “Design Value”">​</a></h2><p><code>useClassComputed</code> may seem simple, but it precisely addresses the most common &quot;style logic coupling&quot; issue in component libraries. It centralizes class name computation logic in one place, ensuring:</p><ul><li>Globally uniform naming conventions</li><li>Predictable and configurable class name generation behavior</li><li>Extremely lean component code (no manual class concatenation)</li><li>Easy future evolution (e.g., integrating theme tokens, automatic dark mode suffixes)</li></ul>',18)])])}const g=t(s,[["render",i]]);export{u as __pageData,g as default};
